changeSet.sql:
DECLARE @enrollmentId BIGINT;
DECLARE @taskId BIGINT;

SELECT @enrollmentId = e.id
FROM enrollment e
WHERE e.completed_at IS NULL;

SELECT @taskId = id FROM task WHERE title = 'c1_m1_l1_task_1';

INSERT INTO student_attempt (enrollment_id, task_id, submitted_at)
VALUES
    (@enrollmentId, @taskId, NULL),
    (@enrollmentId, @taskId, DATEADD(day, -1, GETDATE()));

rollback.sql:
DELETE FROM student_attempt sa
INNER JOIN task t ON sa.task_id = t.id
WHERE t.title = 'c1_m1_l1_task_1';
